      "content": "const _ = require('lodash');
const problemsData = require('../../data/problems.json');

class ProblemsService {
  /**
   * List problems with filtering, paging, and metadata.
   * @param {Object} params
   * @param {string} [params.difficulty] - difficulty filter, e.g. 'Easy', 'Medium', 'Hard'
   * @param {boolean} [params.includeComponents] - whether to include sorted componentLanguages
   * @param {number} [params.limit=50] - max number of results to return
   * @returns {Object} result with problems array and metadata
   */
  static listProblems({ difficulty, includeComponents = false, limit = 50 } = {}) {
    // Defensive: ensure limit is a positive integer and max 50
    limit = Math.min(Math.max(parseInt(limit, 10) || 50, 1), 50);

    // Filter by difficulty if provided
    let filtered = problemsData;
    if (difficulty) {
      filtered = filtered.filter(p => p.difficulty === difficulty);
    }

    // Sort by roundId ascending
    filtered = _.sortBy(filtered, ['roundId']);

    // Apply limit
    const limited = filtered.slice(0, limit);

    // Compose difficulty breakdown for filtered problems
    const difficultyBreakdown = _.countBy(filtered, 'difficulty');

    // Compose componentLanguages if requested
    let componentLanguages = undefined;
    if (includeComponents) {
      // Collect all componentLanguages from limited problems
      const langs = new Set();
      for (const p of limited) {
        if (Array.isArray(p.componentLanguages)) {
          for (const lang of p.componentLanguages) {
            langs.add(lang);
          }
        }
      }
      componentLanguages = Array.from(langs).sort();
    }

    return {
      problems: limited,
      totalProblems: problemsData.length,
      filteredCount: filtered.length,
      appliedLimit: limit,
      difficultyBreakdown,
      ...(includeComponents ? { componentLanguages } : {})
    };
  }
}

module.exports = ProblemsService;
