class ProblemsController {
  /**
   * GET /api/v1/problems
   * Query params: difficulty, includeComponents, limit
   */
  static async list(req, res) {
    try {
      const difficulty = req.query.difficulty;
      const includeComponents = req.query.includeComponents === 'true';
      const limit = req.query.limit ? parseInt(req.query.limit, 10) : undefined;

      const result = ProblemsService.listProblems({ difficulty, includeComponents, limit });

      res.json(result);
    } catch (err) {
      res.status(500).json({ error: 'Internal Server Error' });
    }
  }
}

module.exports = ProblemsController;
